    }
}

// Defence-in-Depth for SQL Injection:

public class DefenceInDepth {
    // Layer 1: Web Application Firewall (WAF)
    //   Blocks known attack patterns before they reach the app

    // Layer 2: Input Validation
    static boolean validateInput(String input) {
        return input != null && input.matches("[a-zA-Z0-9 ]+");
    }

    // Layer 3: Parameterised Queries
    static String safeQuery(String username) {
        return "PreparedStatement: SELECT * FROM users WHERE name = ?";
        // Parameter bound separately, never concatenated
    }

    // Layer 4: Least Privilege Database User
    //   App connects with SELECT-only permissions
    //   Cannot DROP TABLE even if injection succeeds

    // Layer 5: Output Encoding
    static String encodeOutput(String data) {
        return data.replace("<", "&lt;").replace(">", "&gt;");
    }

    // Layer 6: Monitoring and Alerting
    //   Log suspicious queries, alert on anomalies

    public static void main(String[] args) {
        System.out.println("6 layers protect against SQL injection:");
        System.out.println("  1. WAF blocks known patterns");
        System.out.println("  2. Input validation rejects special chars");
        System.out.println("  3. Parameterised queries prevent injection");
        System.out.println("  4. DB permissions limit damage");
        System.out.println("  5. Output encoding prevents XSS from stored data");
        System.out.println("  6. Monitoring detects attempts");
    }
}

// Least Privilege in Database Connections:

public class LeastPrivilege {
    public static void main(String[] args) {
        System.out.println("=== LEAST PRIVILEGE ===");
        System.out.println();
        System.out.println("BAD: One account for everything");
        System.out.println("  app_user: SELECT, INSERT, UPDATE, DELETE, DROP, CREATE");
        System.out.println("  Risk: SQL injection can DROP all tables!");
        System.out.println();
        System.out.println("GOOD: Separate accounts per function");
        System.out.println("  reader_user:  SELECT only");
        System.out.println("  writer_user:  SELECT, INSERT, UPDATE");
        System.out.println("  admin_user:   Full access (used only by admin tools)");
        System.out.println();
        System.out.println("Impact of compromise:");
        System.out.println("  BAD:  Attacker can destroy everything");
        System.out.println("  GOOD: Attacker with reader can only READ data");
    }
}

// Fail-Safe Defaults:

public class FailSafe {
    // BAD: Default ALLOW (blacklist approach)
    static boolean badAccessCheck(String role) {
        if (role.equals("BANNED")) return false;
        return true; // Everyone else gets in!
    }

    // GOOD: Default DENY (whitelist approach)
    static boolean goodAccessCheck(String role) {
        if (role.equals("ADMIN")) return true;
        if (role.equals("USER")) return true;
        return false; // Unknown roles are denied!
    }

    // GOOD: Error handling defaults to deny
    static boolean safeCheck(String role) {
        try {
            return role != null && (role.equals("ADMIN") || role.equals("USER"));
        } catch (Exception e) {
            return false; // On ANY error, deny access
        }
    }

    public static void main(String[] args) {
        System.out.println("BAD  (unknown role): " + badAccessCheck("HACKER"));
        System.out.println("GOOD (unknown role): " + goodAccessCheck("HACKER"));
        System.out.println("SAFE (null role):    " + safeCheck(null));
    }
}

// Complete Mediation:

public class CompleteMediation {
    // BAD: Only checks on initial page load
    static String badApproach(boolean initialCheckPassed, String action) {
        if (initialCheckPassed) {
            return "Performed: " + action; // Cached permission!
        }
        return "Denied";
    }

    // GOOD: Checks every single request
    static String goodApproach(String sessionId, String role, String action) {
        // Check 1: Valid session?
        if (sessionId == null) return "401: Not authenticated";
        // Check 2: Role has permission?
        if (action.equals("DELETE") && !role.equals("ADMIN")) 
            return "403: Not authorised";
        // Check 3: Rate limit?
        // Check 4: Input valid?
        return "200: Performed " + action;
    }

    public static void main(String[] args) {
        System.out.println("BAD:  " + badApproach(true, "DELETE_USER"));
        System.out.println("GOOD: " + goodApproach("sess1", "USER", "DELETE"));
        System.out.println("GOOD: " + goodApproach("sess1", "ADMIN", "DELETE"));
    }
}

// Economy of Mechanism:

public class EconomyOfMechanism {
    public static void main(String[] args) {
        System.out.println("BAD: Custom session management");
        System.out.println("  400 lines of custom code");
        System.out.println("  Likely bugs: race conditions, timing attacks, poor randomness");
        System.out.println();
        System.out.println("GOOD: Framework session management");
        System.out.println("  2 lines: HttpSession session = request.getSession()");
        System.out.println("  Tested by millions of users, audited by security experts");
        System.out.println();
        System.out.println("BAD: Custom encryption");
        System.out.println("  string.charAt(i) ^ key.charAt(i % key.length())");
        System.out.println("  Trivially breakable XOR cipher");
        System.out.println();
        System.out.println("GOOD: Standard library");
        System.out.println("  Cipher.getInstance(\"AES/GCM/NoPadding\")");
        System.out.println("  Industry-standard, peer-reviewed, hardware-accelerated");
    }
}

