// Open Design Principle:

public class OpenDesign {
    public static void main(String[] args) {
        System.out.println("=== OPEN DESIGN ===");
        System.out.println();
        System.out.println("BAD (security through obscurity):");
        System.out.println("  'Nobody knows our API endpoint is /secret-admin'");
        System.out.println("  'Our encryption uses XOR with a fixed key'");
        System.out.println("  'The database is on a non-standard port'");
        System.out.println("  Problem: once discovered, zero protection");
        System.out.println();
        System.out.println("GOOD (open design):");
        System.out.println("  'Our admin endpoint requires ADMIN role + MFA'");
        System.out.println("  'We use AES-256 (public algorithm, secret key)'");
        System.out.println("  'Database requires authentication regardless of port'");
        System.out.println("  Strength: even if attacker knows HOW, they lack the KEYS");
    }
}

// Psychological Acceptability:

public class PsychologicalAcceptability {
    public static void main(String[] args) {
        System.out.println("=== PSYCHOLOGICAL ACCEPTABILITY ===");
        System.out.println();
        System.out.println("BAD (users will bypass):");
        System.out.println("  - Change password every 30 days with 20-char minimum");
        System.out.println("  - Re-authenticate for every page load");
        System.out.println("  - Separate login for each microservice");
        System.out.println("  Result: sticky notes, shared passwords, frustration");
        System.out.println();
        System.out.println("GOOD (security users will actually use):");
        System.out.println("  - Password manager integration");
        System.out.println("  - Biometric authentication (fingerprint/face)");
        System.out.println("  - Single sign-on across services");
        System.out.println("  - Session that lasts 8 hours with idle timeout");
        System.out.println("  Result: strong security that doesn't annoy users");
    }
}

// Protection vs Distribution:

public class ProtectionVsDistribution {
    public static void main(String[] args) {
        System.out.println("=== ARCHITECTURAL TRADE-OFF ===");
        System.out.println();
        System.out.println("CENTRALISED (easy to protect, high impact if breached):");
        System.out.println("  Single database with all user data");
        System.out.println("  Pro: One point to monitor, one backup, one access control");
        System.out.println("  Con: Breach exposes EVERYTHING");
        System.out.println();
        System.out.println("DISTRIBUTED (harder to protect, limited impact per breach):");
        System.out.println("  Separate databases: auth, profiles, financial, logs");
        System.out.println("  Pro: Breach of one does not expose others");
        System.out.println("  Con: More systems to monitor and secure");
        System.out.println();
        System.out.println("BEST PRACTICE: Defence-in-depth hybrid");
        System.out.println("  Centralise authentication (one strong gate)");
        System.out.println("  Distribute data (separate datastores per domain)");
        System.out.println("  Encrypt everything (protection even if breached)");
        System.out.println("  Monitor all access (detect breaches fast)");
    }
}

// Risk Assessment Matrix:

public class RiskAssessment {
    static String assessRisk(int likelihood, int impact) {
        int score = likelihood * impact;
        if (score >= 15) return "CRITICAL";
        if (score >= 10) return "HIGH";
        if (score >= 5)  return "MEDIUM";
        return "LOW";
    }

    public static void main(String[] args) {
        System.out.println("=== DESIGN RISK ASSESSMENT ===");
        // Likelihood: 1-5, Impact: 1-5
        System.out.println("SQL Injection:        " + assessRisk(4, 5)); // CRITICAL
        System.out.println("Brute Force Login:    " + assessRisk(5, 3)); // CRITICAL
        System.out.println("Insider Threat:       " + assessRisk(2, 5)); // HIGH
        System.out.println("DDoS Attack:          " + assessRisk(3, 3)); // MEDIUM
        System.out.println("Physical Server Theft:" + assessRisk(1, 5)); // MEDIUM
        System.out.println("Typo in Error Page:   " + assessRisk(3, 1)); // LOW
    }
}

// Security Patterns vs Anti-Patterns:

public class SecurityPatterns {
    public static void main(String[] args) {
        System.out.println("=== SECURITY PATTERNS ===");
        String[][] patterns = {
            {"Input Validation", "Validate & sanitise ALL input at entry point", "Trust user input, validate only some fields"},
            {"Authentication", "Centralised auth service (OAuth2, SAML)", "Each service has its own login system"},
            {"Error Handling", "Generic errors to user, detailed logs server-side", "Show stack traces and SQL errors to users"},
            {"Database Access", "Parameterised queries / ORM", "String concatenation in queries"},
            {"Secrets Management", "Vault / env vars / config service", "Hard-coded in source code"},
            {"Logging", "Structured audit logs without sensitive data", "Log everything including passwords"}
        };
        for (String[] p : patterns) {
            System.out.println("\n" + p[0] + ":");
            System.out.println("  PATTERN: " + p[1]);
            System.out.println("  ANTI-PATTERN: " + p[2]);
        }
    }
}

