import java.util.*;

public class DefenceLayerSim {
    static boolean wafBlock(String input) {
        return input.contains("<script>") || input.contains("DROP TABLE");
    }
    static boolean inputValidation(String input) {
        return !input.matches("[a-zA-Z0-9 @.]+");
    }
    static boolean parameterisedQuery() {
        return false; // Parameterised queries prevent injection by design
    }
    static boolean leastPrivilege(String action) {
        return action.equals("DROP"); // Read-only DB user cannot DROP
    }

    static void simulateAttack(String attackName, String payload, String action) {
        System.out.println("Attack: " + attackName);
        System.out.println("  Payload: " + payload);
        if (wafBlock(payload)) { System.out.println("  BLOCKED at Layer 1: WAF\n"); return; }
        if (inputValidation(payload)) { System.out.println("  BLOCKED at Layer 2: Input Validation\n"); return; }
        System.out.println("  Layer 3: Parameterised query neutralises injection");
        if (leastPrivilege(action)) { System.out.println("  BLOCKED at Layer 4: DB permissions deny " + action + "\n"); return; }
        System.out.println("  Result: No damage (all layers held)\n");
    }

    public static void main(String[] args) {
        System.out.println("=== DEFENCE-IN-DEPTH SIMULATION ===");
        simulateAttack("XSS via script tag", "<script>alert(1)</script>", "READ");
        simulateAttack("SQL DROP TABLE", "'; DROP TABLE users;--", "DROP");
        simulateAttack("SQL UNION injection", "' UNION SELECT * FROM secrets--", "READ");
        simulateAttack("Normal input", "john.doe@email.com", "READ");
    }
}

import java.util.*;

public class FailSafeDefaults {
    // BAD: Blacklist - deny specific bad roles
    static boolean blacklist(String role) {
        Set<String> banned = Set.of("BANNED", "SUSPENDED");
        if (banned.contains(role)) return false;
        return true; // Unknown = allowed!
    }

    // GOOD: Whitelist - allow specific good roles
    static boolean whitelist(String role) {
        Set<String> allowed = Set.of("ADMIN", "MANAGER", "USER");
        if (allowed.contains(role)) return true;
        return false; // Unknown = denied!
    }

    public static void main(String[] args) {
        String[] tests = {"ADMIN", "USER", "BANNED", "HACKER", null, "", "UNKNOWN"};
        System.out.println("=== FAIL-SAFE DEFAULTS ===");
        System.out.printf("%-10s %-12s %-12s%n", "Role", "Blacklist", "Whitelist");
        for (String r : tests) {
            String display = r == null ? "null" : r.isEmpty() ? "(empty)" : r;
            boolean bl = false, wl = false;
            try { bl = blacklist(r); } catch (Exception e) { }
            try { wl = whitelist(r); } catch (Exception e) { }
            System.out.printf("%-10s %-12s %-12s%n", display, bl ? "ALLOW" : "DENY", wl ? "ALLOW" : "DENY");
        }
    }
}

import java.util.*;

public class CompleteMediationCheck {
    static Map<String, Map<String,Boolean>> endpoints = new LinkedHashMap<>();
    static {
        endpoints.put("GET /", Map.of("auth",false,"authz",false)); // Public
        endpoints.put("GET /login", Map.of("auth",false,"authz",false)); // Public
        endpoints.put("POST /login", Map.of("auth",false,"authz",false)); // Login itself
        endpoints.put("GET /profile", Map.of("auth",true,"authz",true));
        endpoints.put("GET /admin", Map.of("auth",true,"authz",true));
        endpoints.put("POST /transfer", Map.of("auth",true,"authz",true));
        endpoints.put("DELETE /user", Map.of("auth",true,"authz",false)); // BUG!
        endpoints.put("GET /api/data", Map.of("auth",false,"authz",false)); // BUG!
    }

    public static void main(String[] args) {
        Set<String> publicEndpoints = Set.of("GET /", "GET /login", "POST /login");
        System.out.println("=== COMPLETE MEDIATION AUDIT ===");
        int issues = 0;
        for (var entry : endpoints.entrySet()) {
            String ep = entry.getKey();
            Map<String,Boolean> checks = entry.getValue();
            if (publicEndpoints.contains(ep)) {
                System.out.println("[OK]   " + ep + " (public)");
            } else if (!checks.get("auth")) {
                System.out.println("[FAIL] " + ep + " - MISSING AUTHENTICATION!");
                issues++;
            } else if (!checks.get("authz")) {
                System.out.println("[FAIL] " + ep + " - MISSING AUTHORISATION!");
                issues++;
            } else {
                System.out.println("[OK]   " + ep);
            }
        }
        System.out.println("\nIssues found: " + issues);
    }
}

public class RiskCalculator {
    static String calcRisk(String threat, int likelihood, int impact) {
        int score = likelihood * impact;
        String level = score >= 20 ? "CRITICAL" : score >= 12 ? "HIGH" : score >= 6 ? "MEDIUM" : "LOW";
        String colour = score >= 20 ? "[!!!]" : score >= 12 ? "[!! ]" : score >= 6 ? "[!  ]" : "[   ]";
        return String.format("%s %-30s L=%d I=%d Score=%-2d %s", colour, threat, likelihood, impact, score, level);
    }

    public static void main(String[] args) {
        System.out.println("=== DESIGN RISK ASSESSMENT ===");
        System.out.println("L=Likelihood(1-5) I=Impact(1-5) Score=LxI\n");
        System.out.println(calcRisk("SQL Injection", 4, 5));
        System.out.println(calcRisk("Broken Authentication", 4, 5));
        System.out.println(calcRisk("Sensitive Data Exposure", 3, 5));
        System.out.println(calcRisk("XSS (Stored)", 4, 4));
        System.out.println(calcRisk("CSRF", 3, 4));
        System.out.println(calcRisk("Insecure Deserialization", 2, 5));
        System.out.println(calcRisk("DDoS Attack", 3, 3));
        System.out.println(calcRisk("Information Leakage (errors)", 4, 2));
        System.out.println(calcRisk("Clickjacking", 2, 2));
        System.out.println(calcRisk("DNS Misconfiguration", 1, 3));
    }
}

public class EconomyComparison {
    // BAD: 25 lines of custom "encryption"
    static String customEncrypt(String data, String key) {
        char[] result = new char[data.length()];
        for (int i = 0; i < data.length(); i++) {
            result[i] = (char)(data.charAt(i) ^ key.charAt(i % key.length()));
        }
        return new String(result);
    }

    public static void main(String[] args) {
        System.out.println("=== ECONOMY OF MECHANISM ===");
        System.out.println();
        System.out.println("Custom XOR 'encryption':");
        String encrypted = customEncrypt("password", "key");
        System.out.println("  Encrypted: " + encrypted);
        System.out.println("  Decrypted: " + customEncrypt(encrypted, "key"));
        System.out.println("  Lines of code: ~10");
        System.out.println("  Security level: NONE (trivially breakable)");
        System.out.println("  Bugs likely: XOR is symmetric, key reuse, no IV");
        System.out.println();
        System.out.println("Standard library AES:");
        System.out.println("  Cipher c = Cipher.getInstance(\"AES/GCM/NoPadding\");");
        System.out.println("  Lines of code: ~5");
        System.out.println("  Security level: Military grade (AES-256)");
        System.out.println("  Bugs likely: ZERO (millions of users, expert review)");
        System.out.println();
        System.out.println("LESSON: Less custom code = fewer bugs = better security");
    }
}

import java.util.*;

public class SeparationOfDuties {
    static String submitTransfer(String submitter, String amount) {
        return "Transfer $" + amount + " submitted by " + submitter;
    }

    static String approveTransfer(String approver, String submitter, String amount) {
        if (approver.equals(submitter)) {
            return "DENIED: Approver cannot be the same as submitter!";
        }
        return "Transfer $" + amount + " approved by " + approver;
    }

    public static void main(String[] args) {
        System.out.println("=== SEPARATION OF DUTIES ===");
        System.out.println();
        System.out.println(submitTransfer("alice", "50000"));
        System.out.println(approveTransfer("bob", "alice", "50000"));
        System.out.println();
        System.out.println("Attempt self-approval:");
        System.out.println(submitTransfer("eve", "100000"));
        System.out.println(approveTransfer("eve", "eve", "100000"));
    }
}

