public class LayeredSecurity {
    // Layer 1: Presentation (UI)
    static String presentationLayer(String input) {
        if (input.contains("<script>")) return "BLOCKED: XSS attempt in UI layer";
        return "PASS";
    }
    // Layer 2: Application Logic
    static String applicationLayer(String role, String action) {
        if (action.equals("ADMIN_ACTION") && !role.equals("ADMIN")) return "BLOCKED: Unauthorised";
        return "PASS";
    }
    // Layer 3: Data Access
    static String dataLayer(String query) {
        if (query.contains("DROP") || query.contains(";")) return "BLOCKED: Dangerous query";
        return "PASS (using parameterised query)";
    }
    // Layer 4: Database
    static String databaseLayer(String dbUser, String action) {
        if (dbUser.equals("readonly") && !action.equals("SELECT")) return "BLOCKED: Permission denied";
        return "PASS";
    }

    public static void main(String[] args) {
        System.out.println("=== LAYERED ARCHITECTURE SECURITY ===");
        System.out.println();
        System.out.println("Request 1: XSS attempt");
        System.out.println("  UI:     " + presentationLayer("<script>alert(1)</script>"));
        System.out.println();
        System.out.println("Request 2: Unauthorised admin action");
        System.out.println("  UI:     " + presentationLayer("delete user"));
        System.out.println("  App:    " + applicationLayer("USER", "ADMIN_ACTION"));
        System.out.println();
        System.out.println("Request 3: SQL injection that bypasses app layer");
        System.out.println("  UI:     " + presentationLayer("1; DROP TABLE users"));
        System.out.println("  App:    " + applicationLayer("USER", "READ"));
        System.out.println("  Data:   " + dataLayer("1; DROP TABLE users"));
        System.out.println();
        System.out.println("Request 4: Legitimate read");
        System.out.println("  UI:     " + presentationLayer("alice"));
        System.out.println("  App:    " + applicationLayer("USER", "READ"));
        System.out.println("  Data:   " + dataLayer("SELECT * FROM users WHERE name=?"));
        System.out.println("  DB:     " + databaseLayer("readonly", "SELECT"));
    }
}

